module RefModule(input ife,input efe,input fci,output fco,input [15:0]in,output reg [15:0]out);reg [15:0]carry; 
 integer obf_j; 
 always @(fci or in[0]) 
  carry[0] = fci ^ in[0]; 
 always @(in or carry) 
  for (obf_j=1;obf_j<=15;obf_j=obf_j+1) 
  carry[obf_j] = carry[obf_j-1] ^ in[obf_j]; 
 assign fco = carry[15]; 
 always @(ife or efe or carry or in) 
  if (efe) 
  out[15:0] = carry[15:0]; 
  else if (ife) 
  out[15:0] = carry[15:0] | in[15:0]; 
  else 
  out[15:0] = in[15:0]; 
 endmodule
